```Go [sol1-Go]
func resultsArray(nums []int, k int) []int {
    n := len(nums)
    cnt := 0
    ans := make([]int, n - k + 1)
    for i := 0; i < n; i++ {
        if i == 0 || nums[i] - nums[i - 1] != 1 {
            cnt = 1
        } else {
            cnt++
        }
        if cnt >= k {
            ans[i - k + 1] = nums[i]
        } else if i - k + 1 >= 0 {
            ans[i - k + 1] = -1
        }
    }
    return ans
}
```

```Python [sol1-Python]
class Solution:
    def resultsArray(self, nums: List[int], k: int) -> List[int]:
        n = len(nums)
        cnt = 0
        ans = [-1] * (n - k + 1)
        for i in range(n):
            cnt = 1 if i == 0 or nums[i] - nums[i - 1] != 1 else cnt + 1
            if cnt >= k:
                ans[i - k + 1] = nums[i]
        return ans
```

